firmware_template.source:
#include "sht31.h"
#include <Wire.h>
static Adafruit_SHT31 sht;
static float _temp=0, _hum=0;
static unsigned long _last=0;
void sht31_setup() {
  Wire.begin();
  if (!sht.begin(0x44)) { Serial.println("[sht31] Init failed!"); }
  else { Serial.println("[sht31] OK"); }
}
void sht31_loop() {
  if (millis()-_last<2000) return;
  _last=millis();
  _temp=sht.readTemperature();
  _hum=sht.readHumidity();
  if(!isnan(_temp)) Serial.printf("[sht31] T=%.1fC H=%.0f%%\n",_temp,_hum);
}
float sht31_get_temperature(){return _temp;}
float sht31_get_humidity(){return _hum;}
